import { useState } from "react";

export default function Administer() {
  const [data, setData] = useState({});

  const submit = async () => {
    const token = localStorage.getItem("token");

    const res = await fetch("http://localhost:5000/administer", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": token
      },
      body: JSON.stringify(data)
    });

    const blob = await res.blob();

    // Download PDF
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "certificate.pdf";
    a.click();
  };

  return (
    <div>
      <h2>Administer Dose</h2>

      <input placeholder="Citizen ID" onChange={e=>setData({...data,citizen_id:e.target.value})}/>
      <input placeholder="Center ID" onChange={e=>setData({...data,center_id:e.target.value})}/>
      <input placeholder="Dose Number" onChange={e=>setData({...data,dose_number:e.target.value})}/>

      <button onClick={submit}>Submit & Download Certificate</button>
    </div>
  );
}
